{% comment %} TaskNext.AI / ClaudeGram Pro — Landing Section v2 — 2026-03-26 {% endcomment %}

<style>
/* ═══ SHOPIFY SCOPE OVERRIDES ═══ */
body,html{background:#050507!important;}
main,#MainContent,.main-content,.shopify-section-group--header-group+*{background:#050507!important;}
.shopify-section{background:transparent!important;}
/* Force dark on entire page canvas */
body::before{content:'';position:fixed;inset:0;background:#050507;z-index:-1;pointer-events:none;}

/* ═══ RESET & BASE ═══ */
#cgp{font-family:'Inter',system-ui,sans-serif;background:#050507;color:#F1F5F9;line-height:1.6;overflow-x:hidden;padding-bottom:72px}
#cgp *{box-sizing:border-box;margin:0;padding:0}
#cgp a{text-decoration:none}

/* ═══ UTILITIES ═══ */
#cgp .c{max-width:1100px;margin:0 auto;padding:0 24px}
#cgp .gt{background:linear-gradient(135deg,#818CF8 0%,#C084FC 100%);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text}
#cgp .pill{display:inline-flex;align-items:center;gap:6px;padding:6px 14px;border-radius:20px;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;margin-bottom:14px}
#cgp .pi{background:rgba(129,140,248,.12);color:#818CF8;border:1px solid rgba(129,140,248,.25)}
#cgp .pg{background:rgba(16,185,129,.12);color:#10B981;border:1px solid rgba(16,185,129,.25)}
#cgp .pp{background:rgba(192,132,252,.12);color:#C084FC;border:1px solid rgba(192,132,252,.25)}
#cgp .btn{display:inline-flex;align-items:center;gap:8px;padding:13px 28px;border-radius:12px;font-weight:700;font-size:14px;border:none;cursor:pointer;transition:all .25s;letter-spacing:-.01em;font-family:inherit}
#cgp .bp{background:#818CF8;color:#050507;box-shadow:0 0 32px rgba(129,140,248,.35)}
#cgp .bp:hover{background:#9BA3FF;box-shadow:0 0 56px rgba(129,140,248,.55);transform:translateY(-1px);color:#050507}
#cgp .bgh{background:transparent;color:#818CF8;border:1px solid rgba(129,140,248,.4)}
#cgp .bgh:hover{background:rgba(129,140,248,.08);border-color:#818CF8;color:#818CF8}

/* ═══ SCROLL REVEAL ═══ */
#cgp .r{opacity:0;transform:translateY(24px);transition:opacity .65s ease,transform .65s ease}
#cgp .r.v{opacity:1;transform:none}
#cgp .rl{opacity:0;transform:translateX(-28px);transition:opacity .65s ease,transform .65s ease}
#cgp .rl.v{opacity:1;transform:none}
#cgp .rr{opacity:0;transform:translateX(28px);transition:opacity .65s ease,transform .65s ease}
#cgp .rr.v{opacity:1;transform:none}

/* ═══ LIVE DOT ═══ */
#cgp .ldot{width:7px;height:7px;border-radius:50%;background:#10B981;display:inline-block;animation:cgp-pulse 1.4s infinite}
@keyframes cgp-pulse{0%,100%{opacity:1;transform:scale(1)}50%{opacity:.4;transform:scale(.8)}}
@keyframes cgp-float{0%,100%{transform:translateY(0)}50%{transform:translateY(-9px)}}
@keyframes cgp-glow{0%,100%{box-shadow:0 0 30px rgba(129,140,248,.2)}50%{box-shadow:0 0 60px rgba(129,140,248,.45)}}

/* ═══ HERO ═══ */
#cgp .hero{padding:80px 0 64px;text-align:center;position:relative;overflow:hidden;background:#050507}
#cgp .hero::before{content:'';position:absolute;top:-200px;left:50%;transform:translateX(-50%);width:900px;height:700px;background:radial-gradient(ellipse,rgba(129,140,248,.14) 0%,transparent 70%);pointer-events:none}
#cgp .hero::after{content:'';position:absolute;top:60px;right:5%;width:400px;height:400px;background:radial-gradient(ellipse,rgba(192,132,252,.08) 0%,transparent 70%);pointer-events:none;animation:cgp-float 7s ease-in-out infinite}
#cgp .hero .c{position:relative;z-index:1}
#cgp .hero h1{font-size:clamp(38px,6vw,78px);font-weight:900;letter-spacing:-.05em;line-height:1.1;margin:16px 0 16px}
#cgp .hero-sub{font-size:17px;color:#94A3B8;max-width:620px;margin:0 auto 32px;line-height:1.7}
#cgp .hero-ctas{display:flex;gap:12px;justify-content:center;flex-wrap:wrap;margin-bottom:40px}
#cgp .hstats{display:flex;gap:36px;justify-content:center;flex-wrap:wrap;margin-bottom:56px}
#cgp .hs-num{font-size:26px;font-weight:900;letter-spacing:-.03em;background:linear-gradient(135deg,#818CF8,#C084FC);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text}
#cgp .hs-lbl{font-size:11px;color:#475569;font-weight:500;margin-top:2px;text-align:center}
#cgp .lb{display:inline-flex;align-items:center;gap:6px;padding:5px 12px;border-radius:20px;background:rgba(16,185,129,.1);border:1px solid rgba(16,185,129,.3);font-size:12px;font-weight:700;color:#10B981;margin-bottom:10px}

/* ═══ APP WINDOW ═══ */
#cgp .aw{border-radius:16px;overflow:hidden;border:1px solid rgba(255,255,255,.1);box-shadow:0 40px 120px rgba(0,0,0,.8),0 0 60px rgba(129,140,248,.15);background:#0E0E1A}
#cgp .atb{background:#1A1A2E;padding:10px 14px;display:flex;align-items:center;gap:8px;border-bottom:1px solid rgba(255,255,255,.06);flex-shrink:0}
#cgp .atb-dots{display:flex;gap:5px}
#cgp .atb-dot{width:10px;height:10px;border-radius:50%}
#cgp .atb-t{color:#475569;font-size:11px;font-weight:500;margin-left:8px}
#cgp .app-lay{display:grid;grid-template-columns:170px 1fr;min-height:420px}
#cgp .app-sb{background:#0D0D1A;border-right:1px solid rgba(255,255,255,.05);padding:14px 0}
#cgp .sb-logo{padding:0 14px 14px;border-bottom:1px solid rgba(255,255,255,.05);margin-bottom:10px;font-size:12px;font-weight:900;background:linear-gradient(135deg,#818CF8,#C084FC);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text}
#cgp .si{display:flex;align-items:center;gap:8px;padding:8px 14px;font-size:11px;font-weight:500;color:#64748B;cursor:pointer;transition:all .2s}
#cgp .si:hover,#cgp .si.a{background:rgba(129,140,248,.08);color:#818CF8}
#cgp .si.a{border-left:2px solid #818CF8;padding-left:12px}
#cgp .si-ic{font-size:13px;width:15px;text-align:center}
#cgp .app-con{padding:18px;overflow:hidden;background:#0E0E1A}

/* ═══ METRICS ═══ */
#cgp .mrow{display:grid;grid-template-columns:repeat(3,1fr);gap:9px;margin-bottom:14px}
#cgp .mc{background:rgba(255,255,255,.03);border:1px solid rgba(255,255,255,.06);border-radius:11px;padding:13px;position:relative;overflow:hidden}
#cgp .mc::before{content:'';position:absolute;top:0;left:0;right:0;height:2px;background:linear-gradient(90deg,#818CF8,#C084FC)}
#cgp .ml{font-size:9px;color:#475569;font-weight:600;text-transform:uppercase;letter-spacing:.05em;margin-bottom:5px}
#cgp .mv{font-size:20px;font-weight:900;color:#F1F5F9;letter-spacing:-.03em;line-height:1}
#cgp .mch{font-size:10px;font-weight:600;margin-top:3px}
#cgp .up{color:#10B981}#cgp .dn{color:#EF4444}#cgp .nu{color:#64748B}
#cgp .mchart{height:36px;display:flex;align-items:flex-end;gap:2px;margin-top:7px}
#cgp .mb{flex:1;background:rgba(129,140,248,.2);border-radius:2px 2px 0 0}

/* ═══ SECTION LAYOUT ═══ */
#cgp .sec{padding:100px 0;background:#050507}
#cgp .sec-alt{background:linear-gradient(180deg,rgba(129,140,248,.03) 0%,#050507 100%)}
#cgp .sec-alt2{background:linear-gradient(180deg,rgba(192,132,252,.03) 0%,#050507 100%)}
#cgp .split{display:grid;grid-template-columns:1fr 1fr;gap:56px;align-items:center}
#cgp .split.rev{direction:rtl}
#cgp .split.rev>*{direction:ltr}
#cgp .sh2{font-size:clamp(28px,4vw,46px);font-weight:900;letter-spacing:-.04em;line-height:1.15;margin-bottom:14px}
#cgp .sd{font-size:15px;color:#94A3B8;line-height:1.7;margin-bottom:24px}
#cgp .fbs{display:flex;flex-direction:column;gap:10px}
#cgp .fb{display:flex;align-items:flex-start;gap:11px;padding:13px;background:rgba(255,255,255,.03);border:1px solid rgba(255,255,255,.06);border-radius:11px}
#cgp .fb-ic{width:30px;height:30px;border-radius:8px;background:rgba(129,140,248,.12);display:flex;align-items:center;justify-content:center;font-size:14px;flex-shrink:0}
#cgp .fb-tt{font-size:13px;font-weight:700;color:#F1F5F9;margin-bottom:2px}
#cgp .fb-tx{font-size:12px;color:#94A3B8;line-height:1.5}

/* ═══ PROOF BAR ═══ */
#cgp .proof{padding:40px 0;border-top:1px solid rgba(255,255,255,.05);border-bottom:1px solid rgba(255,255,255,.05);background:rgba(255,255,255,.01)}
#cgp .prow{display:flex;gap:44px;align-items:center;justify-content:center;flex-wrap:wrap}
#cgp .pn{font-size:30px;font-weight:900;letter-spacing:-.04em;background:linear-gradient(135deg,#818CF8,#C084FC);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text}
#cgp .pl{font-size:11px;color:#475569;font-weight:500;margin-top:2px;text-align:center}

/* ═══ AGENT CARDS ═══ */
#cgp .agrid{display:grid;grid-template-columns:1fr 1fr;gap:9px}
#cgp .acard{background:rgba(255,255,255,.03);border:1px solid rgba(255,255,255,.06);border-radius:11px;padding:13px}
#cgp .ah{display:flex;align-items:center;justify-content:space-between;margin-bottom:7px}
#cgp .an{font-size:12px;font-weight:700;color:#E2E8F0}
#cgp .ascore{font-size:15px;font-weight:900;color:#818CF8;letter-spacing:-.03em}
#cgp .ala{font-size:10px;color:#64748B;margin-top:5px;padding-top:5px;border-top:1px solid rgba(255,255,255,.05)}
#cgp .asr{display:flex;align-items:center;justify-content:space-between;margin-top:7px}
#cgp .adot{width:6px;height:6px;border-radius:50%;background:#10B981;animation:cgp-pulse 1.4s infinite;flex-shrink:0}
#cgp .ast{font-size:9px;color:#475569}
#cgp .atk{font-size:9px;color:#818CF8;font-weight:600}

/* ═══ CHART ═══ */
#cgp .ca{background:rgba(255,255,255,.02);border:1px solid rgba(255,255,255,.05);border-radius:11px;padding:14px;margin-bottom:11px}
#cgp .ct{font-size:10px;font-weight:600;color:#94A3B8;margin-bottom:10px;text-transform:uppercase;letter-spacing:.04em}
#cgp .lc{height:72px;position:relative;overflow:hidden}
#cgp .lc svg{width:100%;height:100%}

/* ═══ HASHTAG TABLE ═══ */
#cgp .ht{width:100%;border-collapse:collapse;font-size:10px}
#cgp .ht th{text-align:left;color:#475569;font-weight:600;padding:5px 7px;border-bottom:1px solid rgba(255,255,255,.05)}
#cgp .ht td{padding:5px 7px;color:#94A3B8;border-bottom:1px solid rgba(255,255,255,.03)}
#cgp .ht td:first-child{color:#818CF8;font-weight:600}
#cgp .th{background:rgba(239,68,68,.12);color:#EF4444;border:1px solid rgba(239,68,68,.25);border-radius:4px;padding:1px 5px;font-size:8px;font-weight:700}
#cgp .tm{background:rgba(245,158,11,.1);color:#F59E0B;border:1px solid rgba(245,158,11,.25);border-radius:4px;padding:1px 5px;font-size:8px;font-weight:700}
#cgp .tl{background:rgba(16,185,129,.1);color:#10B981;border:1px solid rgba(16,185,129,.25);border-radius:4px;padding:1px 5px;font-size:8px;font-weight:700}

/* ═══ COACH ═══ */
#cgp .csc{width:64px;height:64px;border-radius:50%;border:3px solid #818CF8;display:flex;flex-direction:column;align-items:center;justify-content:center;box-shadow:0 0 18px rgba(129,140,248,.3);flex-shrink:0}
#cgp .cmg{display:grid;grid-template-columns:repeat(3,1fr);gap:7px;margin-top:11px}
#cgp .cm{background:rgba(255,255,255,.03);border:1px solid rgba(255,255,255,.05);border-radius:9px;padding:9px;text-align:center}
#cgp .cmv{font-size:15px;font-weight:900;color:#F1F5F9;line-height:1}
#cgp .cmc{font-size:9px;font-weight:700;margin-top:2px}
#cgp .cml{font-size:9px;color:#475569;margin-top:2px}

/* ═══ CALENDAR ═══ */
#cgp .cal{display:grid;grid-template-columns:repeat(7,1fr);gap:3px;margin-top:7px}
#cgp .ch{font-size:8px;color:#475569;text-align:center;padding:3px;font-weight:600}
#cgp .cd{aspect-ratio:1;border-radius:5px;background:rgba(255,255,255,.02);border:1px solid rgba(255,255,255,.04);display:flex;align-items:center;justify-content:center;font-size:9px;color:#64748B;position:relative;cursor:pointer;transition:all .2s}
#cgp .cd:hover{background:rgba(129,140,248,.08);border-color:rgba(129,140,248,.3)}
#cgp .cd.td{background:rgba(129,140,248,.15);border-color:rgba(129,140,248,.4);color:#818CF8;font-weight:700}
#cgp .cd.hp::after{content:'';position:absolute;bottom:2px;left:50%;transform:translateX(-50%);width:3px;height:3px;border-radius:50%;background:#818CF8}
#cgp .cd.hpm::after{background:linear-gradient(135deg,#818CF8,#C084FC)}

/* ═══ AUTOMATION ═══ */
#cgp .ah3{display:grid;grid-template-columns:repeat(3,1fr);gap:7px;margin-bottom:11px}
#cgp .hc{border-radius:9px;padding:11px;text-align:center}
#cgp .hc.hy{background:rgba(16,185,129,.07);border:1px solid rgba(16,185,129,.2)}
#cgp .hc.hup{background:rgba(245,158,11,.07);border:1px solid rgba(245,158,11,.2)}
#cgp .hc.hd{background:rgba(100,116,139,.05);border:1px solid rgba(100,116,139,.12)}
#cgp .hn{font-size:24px;font-weight:900;line-height:1}
#cgp .hc.hy .hn{color:#10B981}
#cgp .hc.hup .hn{color:#F59E0B}
#cgp .hc.hd .hn{color:#475569}
#cgp .hcl{font-size:9px;color:#64748B;margin-top:3px;line-height:1.3}
#cgp .tr{display:flex;align-items:center;gap:7px;padding:6px 0;border-bottom:1px solid rgba(255,255,255,.04);font-size:10px}
#cgp .tr:last-child{border:none}
#cgp .ti{width:18px;height:18px;border-radius:5px;background:rgba(16,185,129,.12);display:flex;align-items:center;justify-content:center;font-size:9px;flex-shrink:0}
#cgp .tn{color:#CBD5E1;font-weight:600;flex:1}
#cgp .ta{background:rgba(129,140,248,.1);color:#818CF8;border-radius:4px;padding:1px 5px;font-size:8px;font-weight:700}
#cgp .tt{color:#475569;font-size:8px}

/* ═══ PRICING ═══ */
#cgp .pgrid{display:grid;grid-template-columns:1fr 1fr;gap:22px;max-width:740px;margin:0 auto}
#cgp .pc{border-radius:20px;padding:32px;position:relative;overflow:hidden}
#cgp .pc.found{background:rgba(129,140,248,.06);border:2px solid rgba(129,140,248,.35)}
#cgp .pc.reg{background:rgba(255,255,255,.03);border:1px solid rgba(255,255,255,.08)}
#cgp .pb{position:absolute;top:14px;right:14px;background:#818CF8;color:#050507;padding:3px 9px;border-radius:20px;font-size:9px;font-weight:800;text-transform:uppercase;letter-spacing:.05em}
#cgp .pp2{font-size:44px;font-weight:900;letter-spacing:-.05em;line-height:1;margin:14px 0 3px;background:linear-gradient(135deg,#818CF8,#C084FC);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text}
#cgp .pp2 sub{font-size:14px;font-weight:500;-webkit-text-fill-color:#64748B;background:none}
#cgp .pf{list-style:none;margin:20px 0;display:flex;flex-direction:column;gap:9px}
#cgp .pf li{display:flex;align-items:center;gap:7px;font-size:13px;color:#CBD5E1}
#cgp .pf li::before{content:'✓';color:#10B981;font-weight:900;font-size:11px;flex-shrink:0}

/* ═══ TESTIMONIALS ═══ */
#cgp .tgrid{display:grid;grid-template-columns:repeat(3,1fr);gap:18px}
#cgp .tc{background:rgba(255,255,255,.03);border:1px solid rgba(255,255,255,.06);border-radius:15px;padding:22px;transition:border-color .2s;position:relative}
#cgp .tc:hover{border-color:rgba(129,140,248,.25)}
#cgp .ts{color:#F59E0B;font-size:13px;margin-bottom:12px}
#cgp .tt2{color:#CBD5E1;font-size:13px;line-height:1.7;margin-bottom:18px}
#cgp .tauth{display:flex;align-items:center;gap:9px}
#cgp .tav{width:34px;height:34px;border-radius:50%;background:linear-gradient(135deg,#818CF8,#C084FC);display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:800;color:#fff;flex-shrink:0}
#cgp .tnm{font-size:12px;font-weight:700;color:#E2E8F0}
#cgp .thdl{font-size:10px;color:#475569}
#cgp .tgr{position:absolute;top:14px;right:14px;background:rgba(16,185,129,.12);color:#10B981;border:1px solid rgba(16,185,129,.25);border-radius:5px;padding:2px 7px;font-size:9px;font-weight:700}

/* ═══ FAQ ═══ */
#cgp .fi{border-bottom:1px solid rgba(255,255,255,.06);overflow:hidden}
#cgp .fq{padding:18px 0;font-size:14px;font-weight:600;color:#E2E8F0;cursor:pointer;display:flex;align-items:center;justify-content:space-between;gap:14px;user-select:none}
#cgp .fq:hover{color:#818CF8}
#cgp .fic{font-size:17px;color:#818CF8;flex-shrink:0;transition:transform .3s}
#cgp .fa{max-height:0;overflow:hidden;transition:max-height .4s ease,padding .3s}
#cgp .fa.open{max-height:280px;padding-bottom:18px}
#cgp .fa p{color:#94A3B8;font-size:13px;line-height:1.7}

/* ═══ CTA FINAL ═══ */
#cgp .cta-f{border-radius:22px;padding:72px 48px;text-align:center;position:relative;overflow:hidden;background:linear-gradient(135deg,rgba(129,140,248,.1) 0%,rgba(192,132,252,.08) 100%);border:1px solid rgba(129,140,248,.2)}
#cgp .cta-f::before{content:'';position:absolute;top:-100px;left:50%;transform:translateX(-50%);width:600px;height:400px;background:radial-gradient(ellipse,rgba(129,140,248,.15) 0%,transparent 70%);pointer-events:none}
#cgp .cta-f h2{font-size:clamp(28px,4vw,50px);font-weight:900;letter-spacing:-.04em;margin-bottom:14px;position:relative}

/* ═══ FOOTER ═══ */
#cgp .ftr{border-top:1px solid rgba(255,255,255,.06);padding:52px 0 28px;background:#050507}
#cgp .fg{display:grid;grid-template-columns:2fr 1fr 1fr 1fr;gap:36px;margin-bottom:40px}
#cgp .fbt{color:#475569;font-size:13px;line-height:1.7;margin-top:10px;max-width:260px}
#cgp .fc h4{font-size:11px;font-weight:700;color:#64748B;text-transform:uppercase;letter-spacing:.06em;margin-bottom:14px}
#cgp .fc a{display:block;color:#64748B;font-size:13px;margin-bottom:9px;transition:color .2s}
#cgp .fc a:hover{color:#818CF8}
#cgp .fb2{display:flex;align-items:center;justify-content:space-between;padding-top:22px;border-top:1px solid rgba(255,255,255,.04);font-size:12px;color:#334155}

/* ═══ STICKY BAR ═══ */
#cgp-sticky{position:fixed;bottom:0;left:0;right:0;z-index:9999;background:rgba(5,5,7,.96);backdrop-filter:blur(16px);border-top:1px solid rgba(129,140,248,.2);padding:11px 22px;display:flex;align-items:center;justify-content:center;gap:18px;flex-wrap:wrap;font-family:'Inter',system-ui,sans-serif}
#cgp-sticky .sl{display:flex;align-items:center;gap:5px;font-size:13px;font-weight:700;color:#10B981}
#cgp-sticky .st{font-size:13px;color:#94A3B8;font-weight:500}
#cgp-sticky .st strong{color:#F1F5F9}
#cgp-sticky .sc{padding:8px 18px;border-radius:9px;background:#818CF8;color:#050507;font-weight:700;font-size:13px;text-decoration:none;transition:all .2s;font-family:inherit}
#cgp-sticky .sc:hover{background:#9BA3FF;color:#050507}

/* ═══ MULTI-ACCOUNT SECTION ═══ */
#cgp .acc-tabs{display:flex;gap:7px;margin-bottom:14px;overflow-x:auto;padding-bottom:3px}
#cgp .acc-tab{background:rgba(255,255,255,.03);border:1px solid rgba(255,255,255,.06);border-radius:7px;padding:5px 11px;font-size:10px;color:#64748B;white-space:nowrap;flex-shrink:0}
#cgp .acc-tab.active{background:rgba(129,140,248,.14);border-color:rgba(129,140,248,.4);color:#818CF8;font-weight:700}
#cgp .acc-stat-grid{display:grid;grid-template-columns:repeat(5,1fr);gap:7px;margin-bottom:13px}
#cgp .acc-stat{border-radius:9px;padding:10px;text-align:center}
#cgp .acc-num{font-size:17px;font-weight:900;color:#F1F5F9;line-height:1;margin:3px 0}
#cgp .acc-chg{font-size:9px;color:#10B981;font-weight:600}

/* ═══ RESPONSIVE ═══ */
@media(max-width:900px){
  #cgp .split,#cgp .split.rev{grid-template-columns:1fr!important;direction:ltr!important}
  #cgp .app-lay{grid-template-columns:1fr}
  #cgp .app-sb{display:none}
  #cgp .tgrid{grid-template-columns:1fr}
