<script>
(function(){
  // Scroll reveal
  var io=new IntersectionObserver(function(es){
    es.forEach(function(e){if(e.isIntersecting){e.target.classList.add('v');io.unobserve(e.target)}});
  },{threshold:0.08,rootMargin:'0px 0px -30px 0px'});
  document.querySelectorAll('#cgp .r,#cgp .rl,#cgp .rr').forEach(function(el){io.observe(el)});

  // FAQ
  window.cgpFaq=function(el){
    var a=el.nextElementSibling,ic=el.querySelector('.fic'),op=a.classList.toggle('open');
    ic.textContent=op?'−':'+';ic.style.transform=op?'rotate(180deg)':'none';
  };

  // Countdown
  var key='tna_founding_end';
  var stored=localStorage.getItem(key);
  if(!stored){stored=String(Date.now()+72*60*60*1000);localStorage.setItem(key,stored);}
  var end=parseInt(stored,10);
  function pad(n){return n<10?'0'+n:''+n;}
  function tick(){
    var d=end-Date.now();
    if(d<=0){
      ['cgp-sc','ann-countdown'].forEach(function(id){var el=document.getElementById(id);if(el)el.textContent='CLOSED';});
      var fc=document.getElementById('cgp-fc');if(fc)fc.textContent='Founding window has closed.';
      return;
    }
    var h=Math.floor(d/3600000),m=Math.floor((d%3600000)/60000),s=Math.floor((d%60000)/1000);
    var str=pad(h)+':'+pad(m)+':'+pad(s);
    var sc=document.getElementById('cgp-sc');if(sc)sc.textContent=str;
    var fc=document.getElementById('cgp-fc');
    if(fc)fc.innerHTML='⏳ Founding window closes in <strong style="color:#818CF8">'+str+'</strong>';
    setTimeout(tick,1000);
  }
  tick();
})();
</script>

